import{_ as a,o as r,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"81. Cultural And Ceremonial Leave","description":"","frontmatter":{"title":"81. Cultural And Ceremonial Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","ceremonial-leave"]},"headers":[],"relativePath":"ebas/mspp/leave/81-cultural-and-ceremonial-leave.md","filePath":"ebas/mspp/leave/81-cultural-and-ceremonial-leave.md"}'),o={name:"ebas/mspp/leave/81-cultural-and-ceremonial-leave.md"};function l(i,e,s,c,u,d){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_81-cultural-and-ceremonial-leave" tabindex="-1">81. Cultural And Ceremonial Leave <a class="header-anchor" href="#_81-cultural-and-ceremonial-leave" aria-label="Permalink to &quot;81. Cultural And Ceremonial Leave&quot;">​</a></h1><p><strong>a.</strong> The Employer may approve attendance during working hours by an Employee of Aboriginal or Torres Strait Islander descent at any Aboriginal or Torres Strait Islander community meetings, except the Annual General Meetings of Aboriginal or Torres Strait Islander community organisations at which the election of office bearers will occur.</p><p><strong>b.</strong> The Employer may grant an Employee of Aboriginal or Torres Strait Islander descent accrued annual or other leave to attend the Annual General Meetings of Aboriginal or Torres Strait Islander community organisations at which the election of office bearers will occur.</p><p><strong>c.</strong> Ceremonial leave without pay may be granted to an Employee of Aboriginal or Torres Strait Islander descent for ceremonial purposes:</p><p><strong>(i)</strong> connected with the death of a member of the immediate family or extended family (provided that no Employee shall have an existing entitlement reduced as a result of this clause); or</p><p><strong>(ii)</strong> for other ceremonial obligations under Aboriginal or Torres Strait Islander law.</p><p><strong>d.</strong> Ceremonial Leave granted under this clause is in addition to compassionate leave granted under this Agreement.</p><p><strong>e.</strong> Where an Employer receives a request to substitute a public holiday in accordance with <a href="/eba/ebas/mspp/leave/80-public-holidays.html">clause 80.4</a> of this Agreement for a day during NAIDOC week, the Employer will consider all the circumstances including:</p><p><strong>(i)</strong> any reason identified by the Employee with respect to the request; and</p><p><strong>(ii)</strong> the operational requirements of the Employer. An Employer will not unreasonably refuse a request to substitute a public holiday under this subclause.</p><p>Plain language terms: cultural leave, sorry business, ceremonial leave.</p>',11)])])}const h=a(o,[["render",l]]);export{p as __pageData,h as default};
